namespace test_design_eas_database {

  struct Student {
    sqlgen::PrimaryKey<std::string> SNo;
    std::string SName;
    int Sex = 1;
    std::string Birthday;
    int Major;
    float Scorses = 0.0f;
    std::string Remark;
  };

  struct Course {
    sqlgen::PrimaryKey<int> CID;
    std::string CName;
    int Term = 1;
    int CTime;
    float Credit = 0.0f;
  };

  struct Score {
    std::string SNo;
    int CID;
    float Score;
    sqlgen::PrimaryKey<std::tuple<std::string, int>> primary_key;
    sqlgen::ForeignKey<std::string, Student, &Student::SNo> SNo_FK;
    sqlgen::ForeignKey<int, Course, &Course::CID> CID_FK;
  };

  void design_eas_database() {
    // Connect to the SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // Drop tables if they exist using operator| with if_exists
    (sqlgen::drop<Student> | sqlgen::if_exists)(conn);
    (sqlgen::drop<Course> | sqlgen::if_exists)(conn);
    (sqlgen::drop<Score> | sqlgen::if_exists)(conn);

    // Create tables using create_table
    sqlgen::create_table<Student>(conn);
    sqlgen::create_table<Course>(conn);
    sqlgen::create_table<Score>(conn);
  }

}

