struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // Begin transaction
  auto transaction_result = sqlgen::begin_transaction(conn);
  if (!transaction_result) {
    return false;
  }
  auto transaction = *transaction_result;

  try {
    // Verify sufficient funds in sender account
    auto sender_balance_result = (sqlgen::read<Account> | 
                                  sqlgen::where(&Account::account_id == from_account_id))(conn);

    if (!sender_balance_result) {
      transaction->rollback();
      return false;
    }

    auto sender_balance = *sender_balance_result;
    if (sender_balance.balance < amount) {
      transaction->rollback();
      return false;
    }

    // Update sender account: deduct amount
    auto sender_update_result = (sqlgen::update<Account>(sqlgen::set(&Account::balance, sender_balance.balance - amount)) |
                                  sqlgen::where(&Account::account_id == from_account_id))(transaction);

    if (!sender_update_result) {
      transaction->rollback();
      return false;
    }

    // Update receiver account: add amount
    auto receiver_update_result = (sqlgen::update<Account>(sqlgen::set(&Account::balance, sender_balance.balance + amount)) |
                                    sqlgen::where(&Account::account_id == to_account_id))(transaction);

    if (!receiver_update_result) {
      transaction->rollback();
      return false;
    }

    // Commit transaction if all operations succeed
    auto commit_result = sqlgen::commit(transaction);
    if (!commit_result) {
      transaction->rollback();
      return false;
    }

    return true;

  } catch (...) {
    // Rollback on any exception
    transaction->rollback();
    return false;
  }
}

}  // namespace transaction_transfer_funds
