    }

    // Commit transaction if all operations succeed
    auto commit_result = sqlgen::commit(transaction);
    if (!commit_result) {
      transaction->rollback();
      return false;
    }

    return true;

  } catch (...) {
    // Rollback on any exception
    transaction->rollback();
    return false;
  }
}

