  if (!create_result) {
    throw std::runtime_error("Failed to create table");
  }

  // 3. Insert input events into temporary table
  auto insert_result = sqlgen::insert(events)(conn);
  if (!insert_result) {
    throw std::runtime_error("Failed to insert events");
  }

  // 4. Execute complex query to extract temporal components and calculate durations
  auto query = sqlgen::select_from<Event>(
    "event_id"_c,
    "event_name"_c,
    sqlgen::day("start_time"_c).as<"start_day">(),
    sqlgen::month("start_time"_c).as<"start_month">(),
    sqlgen::year("start_time"_c).as<"start_year">(),
