    sqlgen::unixepoch("start_time"_c).as<"start_epoch">(),
    sqlgen::days_between("start_time"_c, "end_time"_c).as<"duration_days">()
  ) | sqlgen::where("end_time"_c.is_not_null());

  // 5. Execute query and map results to TemporalAnalysis objects
  auto result_range = query(conn);

  // 6. Return the analysis results
  std::vector<TemporalAnalysis> analysis_results;
  for (const auto& row : result_range) {
    TemporalAnalysis analysis;
    analysis.event_id = std::get<0>(row);
    analysis.event_name = std::get<1>(row);
    analysis.start_day = std::get<2>(row);
