  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables and insert data
  sqlgen::write(conn, depts);
  sqlgen::write(conn, emps);

  // Helper function to execute queries and collect results
  auto execute_query = [](const auto& query) {
    return (query | sqlgen::to<std::vector<JoinResult>>)(conn).value();
  };

  // INNER JOIN: Employees with assigned departments
  auto inner_query = sqlgen::select_from<Department, "d">(
      "department_name"_d,
      "first_name"_e,
      "last_name"_e, 
      "salary"_e
    ) | sqlgen::inner_join<Employee, "e">("department_id"_d == "department_id"_e);

  // LEFT JOIN: All employees (including those without departments)
  auto left_query = sqlgen::select_from<Employee, "e">(
      "department_name"_d,
      "first_name"_e,
      "last_name"_e,
      "salary"_e
    ) | sqlgen::left_join<Department, "d">("department_id"_e == "department_id"_d);

  // RIGHT JOIN: All departments (including those without employees)
  auto right_query = sqlgen::select_from<Employee, "e">(
      "department_name"_d,
      "first_name"_e,
      "last_name"_e,
      "salary"_e
    ) | sqlgen::right_join<Department, "d">("department_id"_e == "department_id"_d);

  // FULL JOIN: All employees and departments
  auto full_query = sqlgen::select_from<Employee, "e">(
      "department_name"_d,
      "first_name"_e,
      "last_name"_e,
      "salary"_e
    ) | sqlgen::full_join<Department, "d">("department_id"_e == "department_id"_d);

  // Execute all queries and populate JoinAnalysis
  JoinAnalysis analysis;
  analysis.inner_join_results = execute_query(inner_query);
  analysis.left_join_results = execute_query(left_query);
  analysis.right_join_results = execute_query(right_query);
  analysis.full_join_results = execute_query(full_query);

  return analysis;
}

}  // namespace analyze_department_employees
```

