#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

/**
 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
    using namespace sqlgen::literals;

    // Create a SELECT query from Source where value > 100
    auto select_query = select_from<Source>("value"_c) | where("value"_c > 100);

    // Create table Target from the SELECT query
    return create_as<Target>(select_query);
}

}  // namespace create_table_as_select
